                print(f"[*] Set RECON_PATH to {paths[int(index)]}\n")
                DatabaseManagment.directlyModify(["recon_path", paths[int(index)]])
            else:
                print("[-] Invalid recon index.\n")
        else:
            print(f"[-] Unknown category: {category}\n")

